let agentReply = '';
try { agentReply = $('Agent Conversationnel').first().json.output || ''; } catch(e) { agentReply = 'Bonjour ! Je suis disponible pour vous aider dans votre recherche immobilière. Que recherchez-vous ?'; }
let analysis = {};
try { const raw = $('Extracteur Metadonnees').first().json; let output = raw.output; if (typeof output === 'string') { const match = output.match(/\{[\s\S]*\}/); analysis = match ? JSON.parse(match[0]) : JSON.parse(output); } else if (Array.isArray(output)) { const text = output[0]?.content?.[0]?.text || output[0]?.text || '{}'; analysis = typeof text === 'string' ? JSON.parse(text) : text; } else if (output && typeof output === 'object') { analysis = output; } } catch(e) { analysis = {}; }
const toBool = (v) => v === true || v === 'true';
const toStr = (v) => String(v || '').trim();

// Extraire ref_bien depuis réponse agent si absent de l'analyse OpenAI
const refBienFromAgent = analysis.ref_bien || (() => {
  const m = agentReply.match(/\bBG-[A-Z0-9]{4,10}\b/i);
  return m ? m[0].toUpperCase() : '';
})();
return [{ json: { reply: agentReply, interesse: toBool(analysis.interesse), transfert_urgent: toBool(analysis.transfert_urgent), montrer_media: toBool(analysis.montrer_media), visite_programme: toBool(analysis.visite_programme), nom: toStr(analysis.nom), date_rv: toStr(analysis.date_rv), local_interesse: toStr(analysis.local_interesse), ref_bien: toStr(refBienFromAgent) } }];

const items = $input.all();
let visites = [];
for (const item of items) { const data = item.json; if (Array.isArray(data)) { visites = visites.concat(data); } else if (data && typeof data === 'object' && data.id) { visites.push(data); } }
const isNew = visites.length === 0;
return [{ json: { is_new_visite: isNew, existing_count: visites.length } }];

// Recherche intelligente du propriétaire d'un bien
try {
  const localInteresse = $('Parser Analyse').first().json.local_interesse || '';
  const refBien = $('Parser Analyse').first().json.ref_bien || '';

  if (!localInteresse.trim() && !refBien.trim()) {
    return [{ json: { telephone: '', ref_bien: '', _search_error: 'local_interesse et ref_bien vides' } }];
  }

  function normalize(str) {
    if (!str) return '';
    return String(str).toLowerCase().trim()
      .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
      .replace(/[\s\-_.,;\/\\]+/g, ' ').replace(/\s+/g, ' ').trim();
  }

  let allBiens = [];
  try {
    const allItems = $('Chercher Bien').all();
    allBiens = allItems.map(item => item.json);
    if (allBiens.length === 1 && Array.isArray(allBiens[0])) { allBiens = allBiens[0]; }
  } catch(e) {
    return [{ json: { telephone: '', ref_bien: '', _search_error: 'Erreur lecture: ' + e.message } }];
  }

  // Recherche par REF d'abord
  if (refBien.trim()) {
    const refNorm = refBien.trim().toUpperCase();
    const exactMatch = allBiens.find(row => row.ref_bien && row.ref_bien.toUpperCase() === refNorm);
    if (exactMatch) {
      const tel = exactMatch.telephone_bien || exactMatch.telephone || exactMatch.telephone_expediteur || '';
      return [{ json: Object.assign({}, exactMatch, { telephone: tel, _match_score: 100, _match_method: 'ref_bien' }) }];
    }
  }

  // Recherche par mots-clés
  const searchTerms = normalize(localInteresse).split(' ').filter(w => w.length > 2);
  if (searchTerms.length === 0) {
    return [{ json: { telephone: '', ref_bien: '', _search_error: 'Termes insuffisants' } }];
  }

  let bestMatch = null;
  let bestScore = 0;
  for (const row of allBiens) {
    if (!row || !row.type_de_bien) continue;
    const rowText = normalize([row.type_de_bien, row.zone_geographique, row.commune, row.quartier, row.prix, row.caracteristiques].filter(Boolean).join(' '));
    let score = 0;
    for (const term of searchTerms) { if (rowText.includes(term)) score++; }
    const matchPercent = (score / searchTerms.length) * 100;
    if (matchPercent >= 40 && matchPercent > bestScore) { bestScore = matchPercent; bestMatch = row; }
  }

  if (bestMatch) {
    const tel = bestMatch.telephone_bien || bestMatch.telephone || bestMatch.telephone_expediteur || '';
    return [{ json: Object.assign({}, bestMatch, { telephone: tel, _match_score: bestScore, _match_method: 'keywords' }) }];
  } else {
    return [{ json: { telephone: '', ref_bien: '', _search_error: 'Aucun bien trouvé pour: ' + localInteresse } }];
  }
} catch(e) {
  console.log('Recherche Proprietaire erreur:', e.message);
  return [{ json: { telephone: '', ref_bien: '', _search_error: e.message } }];
}

// Anti-boucle: filtre messages du bot + déduplication TTL 5min

const input = $input.first().json;

// 1. Ignorer messages envoyés par le bot
if (input.fromMe === true) return [];

// 2. Vérifier messageId
const msgId = String(input.messageId || '').trim();
if (!msgId) return [];

// 3. Cache TTL via static data
const staticData = $getWorkflowStaticData('node');
if (!staticData.seenMessages) staticData.seenMessages = {};

const now = Date.now();
const TTL = 5 * 60 * 1000; // 5 minutes

// Purger les anciens
for (const id of Object.keys(staticData.seenMessages)) {
  if (now - staticData.seenMessages[id] > TTL) {
    delete staticData.seenMessages[id];
  }
}

// Si déjà traité dans les 5 dernières minutes, ignorer
if (staticData.seenMessages[msgId]) return [];

// Marquer comme traité
staticData.seenMessages[msgId] = now;

return [input];

// ============================================================
// ⚙️  CONFIG NUMÉROS - Éditez les valeurs ci-dessous
// ============================================================

const NUMERO_AGENCE       = "2250142694380"; // ← Numéro de l'agence
const NUMERO_PROPRIETAIRE = "2250789263373"; // ← Numéro propriétaire (fallback)

// ============================================================
// Ne pas modifier en-dessous de cette ligne
