    json: Object.assign({}, item.json, {
      numero_agence: NUMERO_AGENCE,
      numero_proprietaire: NUMERO_PROPRIETAIRE
    })
  };
});

// Validation Webhook - pass-through si pas de signature (Wasender standard)
// Bloque uniquement si signature présente mais invalide
try {
  const WASENDER_SECRET = '1762ea865bd12948e715bbd6f9e03ef7';
  const json = $input.first().json;
  const headers = json.headers || {};

  const rawBody = json.rawBody
    || (typeof json.body === 'string' ? json.body : null)
    || JSON.stringify(json.body)
    || '';

  const receivedSig = (
    headers['x-webhook-signature'] ||
    headers['x-wasender-signature'] ||
    headers['x-hub-signature-256'] ||
    ''
  ).replace('sha256=', '').toLowerCase();

  // Pas de signature → Wasender ne signe pas → laisser passer
  if (!receivedSig) {
    console.log('Pas de signature - pass-through');
    return $input.all();
  }

  // Signature présente → valider HMAC
  const crypto = require('crypto');
  const expected = crypto
    .createHmac('sha256', WASENDER_SECRET)
    .update(rawBody)
    .digest('hex')
    .toLowerCase();

  if (expected !== receivedSig) {
    console.log('Signature invalide - rejet');
    return [{ json: { error: true, message: 'Signature invalide', status: 401 } }];
  }

  return $input.all();
} catch (e) {
  console.log('Erreur validateur:', e.message, '- pass-through');
  return $input.all();
}

// Sanitiser les inputs pour eviter injection
// IMPORTANT: On préserve la structure COMPLÈTE du webhook ici
// Le Normaliser Webhook va ensuite extraire les données de la bonne structure
try {
  const data = $input.first().json;

  const sanitize = (str) => {
    if (!str || typeof str !== 'string') return str;
    return str.replace(/[\x00-\x1f]/g, '').substring(0, 2000).trim();
  };

  // Sanitiser les champs texte dans body.data.messages si présent
  const body = data.body || data;
  const msgData = body.data || {};
  const messages = msgData.messages || {};
  const message = messages.message || {};

  // Sanitiser les champs texte accessibles à ce stade
  if (messages.messageBody) messages.messageBody = sanitize(messages.messageBody);
  if (messages.pushName) messages.pushName = sanitize(messages.pushName);
  if (message.conversation) message.conversation = sanitize(message.conversation);
  if (message.extendedTextMessage && message.extendedTextMessage.text) {
    message.extendedTextMessage.text = sanitize(message.extendedTextMessage.text);
  }

  // Retourner la structure ORIGINALE intacte (avec les modifications sanitisées)
  return [{ json: data }];
} catch (e) {
  // Ne jamais bloquer - retourner l'input original
  return $input.all();
}

// ===== NORMALISER LA STRUCTURE DU WEBHOOK =====
// Gestion robuste des LIDs WhatsApp (Linked IDs vs vrais numéros)
try {
  const body = $input.first().json.body || $input.first().json;
  const event = body.event || '';
  const data = body.data || body;

  if (event && !event.includes('message')) return [];

  let msg = null;
  if (Array.isArray(data.messages)) msg = data.messages[0];
  else if (data.messages && typeof data.messages === 'object') msg = data.messages;
