  const typeMapping = {
    'appartement': 'APT', 'studio': 'STU', 'chambre': 'CHB', 'maison': 'MAS', 'villa': 'VIL',
    'duplex': 'DPX', 'terrain': 'TER', 'bureau': 'BUR', 'magasin': 'MAG', 'local': 'LOC'
  };
  const typeLow = (extracted.type_de_bien || '').toLowerCase();
  const typeKey = Object.keys(typeMapping).find(k => typeLow.includes(k));
  const typeCode = typeKey ? typeMapping[typeKey] : (typeLow.substring(0, 3).toUpperCase() || 'BIE');
  const communeStr = (extracted.commune || '').substring(0, 3).toUpperCase() || 'ABJ';
  const shortUuid = 'xxxxxxxx'.replace(/[x]/g, function() { return Math.floor(Math.random()*16).toString(16).toUpperCase(); });
  const ref_bien = typeCode + '-' + communeStr + '-' + shortUuid;

  // Hash djb2 pure JS
  function djb2Hash(str) {
    let h = 5381;
    for (let i = 0; i < str.length; i++) h = ((h << 5) + h + str.charCodeAt(i)) & 0xFFFFFFFF;
    return (h >>> 0).toString(16).padStart(8, '0');
  }
  const contentHash = djb2Hash(JSON.stringify({
    type: typeLow,
    prix: String(extracted.prix || ''),
    commune: (extracted.commune || '').toLowerCase(),
    quartier: (extracted.quartier || '').toLowerCase(),
    caract: (extracted.caracteristiques || '').substring(0, 100).toLowerCase()
  }));

  // Verifier doublons
  let annonces = [];
  try { annonces = $('Charger Annonces Recentes').all().map(i => i.json); } catch(e) { annonces = []; }
  const isDuplicate = annonces.some(a => a.content_hash === contentHash);
  if (isDuplicate) {
    console.log('Doublon detecte: ' + contentHash);
    return [];
  }

  // Recuperer les donnees source depuis Extraire Donnees Publication
  let sourcePub = {};
  try { sourcePub = $('Extraire Donnees Publication').first().json; } catch(e) {}

  // Mapper vers schema Supabase locaux + enrichir avec donnees source
  const annonce = {
    ref_bien,
    content_hash: contentHash,
    type_de_bien: extracted.type_de_bien || '',
    type_offre: extracted.type_offre || '',
    zone_geographique: extracted.zone_geographique || '',
    commune: extracted.commune || '',
    quartier: extracted.quartier || '',
    prix: extracted.prix || '',
    telephone_bien: extracted.telephone || '',
    caracteristiques: extracted.caracteristiques || '',
    publie_par: extracted.publie_par || '',
    meubles: extracted.meubles === 'Oui' ? true : false,
    chambre: extracted.chambre || '',
    disponible: true,
    status: 'active',
    // Donnees source pour Sauvegarder Nouvelle Annonce
    _source_telephone: sourcePub.telephone || '',
    _source_expediteur: sourcePub.expediteur || '',
    _source_groupe_nom: sourcePub.groupe || '',
    _source_groupe_jid: sourcePub.groupe_jid || '',
    _source_lien_image: sourcePub.lien_image || '',
    _source_message: sourcePub.message || '',
    _source_publication_id: sourcePub.publication_id || ''
  };

  console.log('Annonce: ' + ref_bien + ' | ' + annonce.type_de_bien + ' | ' + annonce.commune);
  return [{ json: annonce }];
} catch(e) {
  console.log('Detecteur Doublons erreur:', e.message);
  return [];
}

